texttool_globals_dialog_message___add_shortcut_message = TextObject(bs_BA="Dodati prečicu za pregled aplikacije?", cs_CZ="Přidat zkratku do přehledu aplikací?", da_DK="Tilføj genvej til appoversigt?", de_DE="Shortcut zu App-Übersicht hinzufügen?", el_GR="Να προστεθεί συντόμευση προς την επισκόπηση των\nεφαρμογών;", en_GB="Add shortcut to app overview?", es_ES="¿Añadir atajo a la aplicación?", fi_FI="Lisätäänkö sovellusten yleiskuvan pikavalinta?", fr_FR="Ajouter un raccourci vers la vue d'ensemble des\napplications?", hr_HR="Dodati prečac za pregled aplikacija?", hu_HU="Parancsikon hozzáadása az alkalmazásáttekintéshez?", it_IT="Aggiungere shortcut alla panoramica app?", nl_NL="Shurtcut naar app-overzicht toevoegen?", no_NO="Legge snarvei til appoversikten?", pl_PL="Dodać skrót do przeglądu aplikacji?", pt_PT="Introduzir atalho para apresentação da app?", ro_RO="Adăugare comandă rapidă la prezentare generală aplicaţii?", ru_RU="Добавить ярлык в обзор приложений?", sk_SK="Pridať Shortcut k prehľadu aplikácií?", sl_SI="Ali želite dodati bližnjico za pregled aplikacij?", sr_RS="Dodati prečicu za pregled aplikacija?", sv_SE="Lägg till genväg till appöversikten?", tr_TR="Kısayol uygulamalara genel bakışa eklensin mi?", uk_UA="Додати ярлик в огляд додатків?")
texttool_globals_dialog_message___app_grid__confirm_display_dialog__message_app_already_on_center_display = TextObject(bs_BA="%1 je trenutno aktivan u MMI i ne može se\nkoristiti istovremeno na oba displeja.\nŽelite li ovdje otvoriti aplikaciju?", cs_CZ="%1 je aktuálně aktivní v MMI a nelze používat současně na obou\ndisplejích. Chcete zde otevřít aplikaci?", da_DK="%1 p.t. aktiv i MMI og kan ikke anvendes samtidig\ni begge displays. Vil du åbne appen her?", de_DE="%1 ist aktuell im MMI aktiv und kann nicht\ngleichzeitig auf beiden Displays verwendet werden.\nMöchtest du die App hier öffnen?", el_GR="O/H/Το %1 είναι τώρα ενεργός/-ή/-ό στο MMI\nκαι δεν μπορεί να χρησιμοποιηθεί ταυτόχρονα και στις δύο\nοθόνες. Θέλετε να ανοίξετε εδώ την εφαρμογή;", en_GB="%1 is currently active on the MMI and cannot\nbe used on both displays at the same time. Would you like to\nopen the app here?", es_ES="La aplicación %1 está activa en el MMI y no se puede utilizar\nsimultáneamente en las dos pantallas. ¿Desea abrir la App aquí?", fi_FI="%1 on tällä hetkellä aktiivisena MMI:ssä eikä\nsitä voi käyttää samanaikaisesti molemmilla näytöillä.\nHaluatko avata sovelluksen tähän?", fr_FR="L'application %1 est actuellement utilisée dans le MMI et ne\npeut pas être utilisée simultanément sur les deux écrans.\nSouhaitez-vous ouvrir l'application ici?", hr_HR="Aplikacija %1 trenutačno je aktivna u MMI-ju\ni ne može se koristiti istovremeno na oba zaslona.\nŽelite li aplikaciju otvoriti tu?", hu_HU="%1 jelenleg aktív az MMI-ben, és nem lehet\negyszerre használni minkét kijelzőn.\nMeg szeretnéd itt nyitni az alkalmazást?", it_IT="Al momento l'app %1 è attiva nell'MMI e non può essere\nutilizzata contemporaneamente su entrambi i display. Aprire qui l'app?", nl_NL="%1 is momenteel in MMI actief en kan niet tegelijkertijd op\nbeide displays worden gebruikt. Wil je de app hier openen?", no_NO="%1 brukes i MMI nå og kan ikke brukes på\nbegge displayene samtidig. Vil du åpne appen her?", pl_PL="%1 jest obecnie aktywna w MMI i nie można\nz niej korzystać na obu wyświetlaczach.\nCzy chcesz otworzyć aplikację tutaj?", pt_PT="%1 está atualmente ativo no MMI e não pode ser utilizado em\nsimultâneo nos dois ecrãs. Queres abrir aqui a aplicação?", ro_RO="%1 este momentan activ în MMI şi nu poate fi utilizat simultan\npe ambele afişaje. Doriţi să deschideţi aici aplicaţia?", ru_RU="%1 в настоящее время активно в MMI и не может\nиспользоваться на обоих дисплеях одновременно.\nХотите открыть приложение здесь?", sk_SK="%1 je momentálne aktívny v systéme MMI a nie je možné ho\npoužiť na oboch displejoch súčasne. Chcete aplikáciu otvoriť tu?", sl_SI="Aplikacija %1 je trenutno aktivna v sistemu MMI in je ni mogoče\nistočasno uporabljati na obeh zaslonih. Ali želite aplikacijo odpreti tukaj?", sr_RS="%1 je trenutno aktivan u MMI i ne može se\nkoristiti istovremeno na oba displeja.\nDa li želite da otvorite aplikaciju ovde?", sv_SE="%1 är aktiv i MMI och kan inte användas samtidigt på båda\ndisplayer. Vill du öppna appen här?", tr_TR="%1 şu anda MMI'da aktif ve aynı anda her iki ekranda\nkullanılamaz. Uygulamayı burada açmak ister misin?", uk_UA="%1 наразі активна у MMI і не може використовуватися на\nобох дисплеях одночасно. Хочете відкрити програму тут?")
texttool_globals_dialog_message___app_grid__confirm_display_dialog__message_app_already_on_passenger_display = TextObject(bs_BA="%1 je trenutno aktivan u MMI displeju\nsuvozača i ne može se koristiti istovremeno na oba displeja.\nŽelite li ovdje otvoriti aplikaciju?", cs_CZ="%1 je aktuálně aktivní na displeji MMI\nspolujezdce a nelze používat současně na obou displejích.\nChcete zde otevřít aplikaci?", da_DK="%1 p.t. aktiv på MMI-display til forsædepassager\nog kan ikke anvendes samtidig i begge displays. Vil du åbne appen her?", de_DE="%1 ist aktuell im MMI Beifahrerdisplay aktiv\nund kann nicht gleichzeitig auf beiden Displays verwendet\nwerden. Möchtest du die App hier öffnen?", el_GR="O/H/Το %1 είναι τώρα ενεργός/-ή/-ό στην οθόνη\nσυνοδηγού του MMI και δεν μπορεί να χρησιμοποιηθεί ταυτόχρονα\nκαι στις δύο οθόνες. Θέλετε να ανοίξετε εδώ την εφαρμογή;", en_GB="%1 is currently active on the MMI front\npassenger display and cannot be used on both displays at\nthe same time. Would you like to open the app here?", es_ES="La aplicación %1 está activa en la pantalla\ndel MMI del acompañante y no se puede utilizar simultáneamente\nen las dos pantallas. ¿Desea abrir la App aquí?", fi_FI="%1 on tällä hetkellä aktiivisena MMI:n etumatkustajan\nnäytöllä eikä sitä voi käyttää samanaikaisesti molemmilla näytöillä.\nHaluatko avata sovelluksen tähän?", fr_FR="L'application %1 est actuellement utilisée\nsur l'écran MMI du passager avant et ne peut pas être\nutilisée simultanément sur les deux écrans.\nSouhaitez-vous ouvrir l'application ici?", hr_HR="Aplikacija %1 trenutačno je aktivna na\nsuvozačevom zaslonu MMI-ja i ne može se koristiti\nistovremeno na oba zaslona. Želite li aplikaciju otvoriti tu?", hu_HU="%1 jelenleg aktív az MMI utaskijelzőn, és nem lehet\negyszerre használni minkét kijelzőn Meg szeretnéd itt nyitni az alkalmazást?", it_IT="Al momento l'app %1 è attiva nell'MMI del\ndisplay passeggero anteriore e non può essere utilizzata\ncontemporaneamente su entrambi i display. Aprire qui l'app?", nl_NL="%1 is momenteel in het MMI-bijrijdersdisplay\nactief en kan niet tegelijkertijd op beide displays worden\ngebruikt. Wil je de app hier openen?", no_NO="%1 brukes på MMI-passasjerdisplayet nå og\nkan ikke brukes på begge displayene samtidig. Vil du åpne appen her?", pl_PL="%1 jest obecnie aktywna na ekranie MMI\npasażera i nie można z niej korzystać na obu wyświetlaczach.\nCzy chcesz otworzyć aplikację tutaj?", pt_PT="%1 está atualmente ativo no ecrã do\npassageiro do MMI e não pode ser utilizado em simultâneo\nnos dois ecrãs. Queres abrir aqui a aplicação?", ro_RO="%1 este momentan activ în afişajul MMI\npasager faţă şi nu poate fi utilizat simultan pe ambele\nafişaje. Doriţi să deschideţi aici aplicaţia?", ru_RU="%1 в настоящее время активно на дисплее\nMMI переднего пассажира и не может использоваться на\nобоих дисплеях одновременно. Хотите открыть приложение здесь?", sk_SK="%1 je momentálne aktívny v systéme MMI na\ndispleji spolujazdca a nie je možné ho použiť na oboch\ndisplejoch súčasne. Chcete aplikáciu otvoriť tu?", sl_SI="Aplikacija %1 je trenutno aktivna na sovoznikovem\nzaslonu sistema MMI in je ni mogoče istočasno uporabljati na obeh zaslonih.\nAli želite aplikacijo odpreti tukaj?", sr_RS="%1 je trenutno aktivan na MMI displeju\nsuvozača i ne može se koristiti istovremeno na oba displeja.\nDa li želite da otvorite aplikaciju ovde?", sv_SE="%1 är aktiv på MMI-passagerardisplayen och\nkan inte användas samtidigt på båda displayer. Vill du öppna appen här?", tr_TR="%1 şu anda MMI ön yolcu ekranında aktif ve\naynı anda her iki ekranda kullanılamaz. Uygulamayı burada açmak ister misin?", uk_UA="%1 наразі активна на дисплеї MMI\nпереднього пасажира і не може використовуватися на\nобох дисплеях одночасно. Хочете відкрити програму тут?")
texttool_globals_dialog_message___dashboard__navi_bought_later__message = TextObject(bs_BA="Da li za navigaciju treba dodati jednu pločicu na kontrolnoj tabli?\n(Napomena: Pločica se postavlja na posljednja dva mjesta na\nkontrolnoj tabli.)", cs_CZ="Má se pro navigaci přidat dlaždice na dashboard?\n(Poznámka: Dlaždice se umístí na obě poslední\nmísta dashboardu.)", da_DK="Skal der tilføjes en flade for navigationen på dashboardet?\n(Bemærk: Fladen placeres på dashboardets sidste to steder.)", de_DE="Soll für die Navigation eine Kachel zum Dashboard hinzugefügt werden?\n(Hinweis: Die Kachel wird auf den letzten beiden Stellen des\nDashboards platziert.)", el_GR="Να προστεθεί για την πλοήγηση ένα πλακίδιο στον πίνακα ελέγχου;\n(Υπόδειξη: Το πλακίδιο θα τοποθετηθεί στις τελευταίες δύο\nθέσεις του πίνακα ελέγχου.)", en_GB="Should a navigation tile be added to the dashboard?\n(Note: the tile will be placed on the last two positions on the dashboard.)", es_ES="¿Añadir al panel de control un botón virtual para la navegación?\n(Nota: el botón virtual aparecerá en las dos últimas posiciones\ndel panel de control.)", fi_FI="Lisätäänkö kuvake kojelautaan navigointia varten?\n(Huomio: Kuvake sijoitetaan kojelaudan kahdelle\nviimeiselle paikalle.)", fr_FR="Est-ce qu'une icône doit être ajoutée au tableau de bord pour la navigation?\n(nota: l'icône sera placée sur les deux derniers emplacements du\ntableau de bord)", hr_HR="Treba li za navigaciju dodati pločicu na dashboardu\n(napomena: pločica će se smjestiti na zadnja dva\nmjesta dashboarda.)", hu_HU="Hozzá szeretnél adni egy csempét az irányítópulthoz a navigáció számára?\n(Megjegyzés: a csempe az irányítópult utolsó két helyére kerül.)", it_IT="Aggiungere alla dashboard un riquadro per la navigazione?\n(Avvertenza: il riquadro viene posizionato sulle ultime due\nposizioni della dashboard.)", nl_NL="Moet voor de navigatie een tegel worden toegevoegd aan het dashboard?\n(opmerking: de tegel wordt op de laatste twee plekken van\nhet dashboard geplaatst.)", no_NO="Skal det legges til et ikon for navigasjon på skrivebordet?\n(Merk: Ikonet plasseres på de to siste plassene\npå skrivebordet.)", pl_PL="Czy dodać przycisk nawigacji na pulpicie?\n(Wskazówka: przycisk zostanie umieszczony\nna ostatnich dwóch miejscach pulpitu).", pt_PT="Queres que introduza uma caixa do painel de bordo para a navegação?\n(Observação: A caixa será colocada nos dois últimos locais\ndo painel de bordo.)", ro_RO="Să fie adăugată pentru navigaţie o casetă pe Dashboard?\n(indicaţie: caseta va fi amplasată în ultimele două poziţii\ndin Dashboard.)", ru_RU="Хотите добавить плитку на панель инструментов для навигации?\n(Примечание: плитка будет размещена на двух последних\nячейках панели инструментов.)", sk_SK="Chcete pridať dlaždicu na Dashboard pre navigáciu?\n(Upozornenie: dlaždica bude umiestnená na posledné dve\nmiesta na Dashboarde.)", sl_SI="Ali želite za navigacijo dodati ploščico na nadzorni plošči?\n(Napotek: ploščica bo nameščena na zadnji dve mesti na\nnadzorni plošči.)", sr_RS="Da li treba dodati polje za navigaciju na kontrolnoj tabli?\n(Napomena: Polje će biti postavljeno na poslednja dva mesta\nkontrolne table.)", sv_SE="Vill du lägga till en panel på instrumentbrädan för navigering?\n(Observera: Panelen placeras på de senaste båda ställena\npå instrumentbrädan.)", tr_TR="Navigasyon için gösterge paneline bir karo eklensin mi?\n(Not: Karo, gösterge panelinin son iki konumuna yerleştirilir.)", uk_UA="Хочете додати плитку на панель інструментів для навігації?\n(Примітка: плитка буде розміщена на двох останніх місцях\nпанелі інструментів.)")
texttool_globals_dialog_message___dashboard__tile__replace_confirmation_dialog__message = TextObject(bs_BA="Dodavanjem ove pločice se uklanja neka druga pločica.\nZaista nastaviti?", cs_CZ="Přidání této dlaždice odstraní jinou dlaždici.\nOpravdu pokračovat?", da_DK="Tilføjelse af denne flade fjerner en anden flade.\nVil du virkelig fortsætte?", de_DE="Das Hinzufügen dieser Kachel entfernt eine andere Kachel.\nWirklich fortfahren?", el_GR="Με την προσθήκη αυτού του πλακιδίου θα αφαιρεθεί ένα άλλο πλακίδιο.\nΘέλετε σίγουρα να συνεχίσετε;", en_GB="Adding this tile will remove another tile. Continue anyway?", es_ES="Si añade este botón virtual, se eliminará otro.\n¿Continuar igualmente?", fi_FI="Tämän kuvakkeen lisääminen poistaa jonkin toisen kuvakkeen.\nHaluatko varmasti jatkaa?", fr_FR="L'ajout de cette icône entraînera la suppression d'une autre icône.\nSouhaitez-vous vraiment poursuivre?", hr_HR="Dodavanjem te pločice uklonit će se neka druga.\nŽelite li uistinu nastaviti?", hu_HU="Ennek a csempének a hozzáadása eltávolít egy másik csempét.\nBiztosan folytatni szeretnéd?", it_IT="Aggiungendo questo riquadro verrà rimosso un altro riquadro. Procedere?", nl_NL="Met het toevoegen van deze tegel wordt een andere tegel verwijderd.\nWil je echt doorgaan?", no_NO="Hvis du legger til dette ikonet, vil et annet ikon bli fjernet.\nEr du sikker på at du vil fortsette?", pl_PL="Dodanie tego przycisku usunie inny przycisk.\nCzy na pewno kontynuować?", pt_PT="A introdução desta caixa origina a remoção de uma outra.\nQueres mesmo continuar?", ro_RO="Adăugarea acestei casete şterge o altă casetă.\nDoriţi într-adevăr să continuaţi?", ru_RU="Добавление этой плитки удалит другую плитку.\nДействительно продолжить?", sk_SK="Pridaním tejto dlaždice sa odstráni iná dlaždica.\nSkutočne chcete pokračovať?", sl_SI="Z dodajanjem te ploščice boste odstranili drugo ploščico.\nAli res želite nadaljevati?", sr_RS="Dodavanjem ovog polja uklanjate drugo polje.\nStvarno nastaviti?", sv_SE="Om du lägger panelen kommer en annan panel att tas bort.\nVill du fortsätta?", tr_TR="Bu karonun eklenmesi başka bir karoyu kaldırır.\nGerçekten devam edilsin mi?", uk_UA="Додавання цієї плитки видалить іншу плитку.\nДійсно продовжити?")
texttool_globals_dialog_message___phone_missing_permissions_reason = TextObject(bs_BA="Kontrolnoj tabli su potrebna dodatna ovlaštenja za pristup telefonskim podacima.\nŽelite li sada dodijeliti ova ovlaštenja?", cs_CZ="Přístrojový panel vyžaduje další oprávnění pro přístup k údajům telefonu. Chcete\ntato oprávnění udělit nyní?", da_DK="Dashboardet kræver yderligere autorisationer for at kunne få adgang til\ntelefondataene. Vil du tildele disse autorisationer nu?", de_DE="Das Dashboard benötigt zusätzliche Berechtigungen, um auf die Telefondaten\nzugreifen zu können. Möchtest du diese Berechtigungen jetzt erteilen?", el_GR="Ο πίνακας ελέγχου χρειάζεται πρόσθετες εξουσιοδοτήσεις, ώστε να μπορεί να έχει\nπρόσβαση στα δεδομένα του τηλεφώνου. Θέλετε να χορηγήσετε τώρα αυτές τις\nεξουσιοδοτήσεις;", en_GB="The dashboard requires additional permissions to access telephone data. Do you\nwant to grant these permissions now?", es_ES="El panel de control precisa más permisos para acceder a los datos del teléfono.\n¿Desea conceder estos permisos ahora?", fi_FI="Kojelauta tarvitsee lisäoikeuksia puhelintietoihin pääsemiseksi. Haluatko myöntää\nnämä oikeudet nyt?", fr_FR="Le tableau de bord requiert des autorisations supplémentaires pour pouvoir\naccéder aux données du téléphone. Souhaitez-vous accorder ces autorisations\nmaintenant?", hr_HR="Dashboard treba dodatna odobrenja kako bi pristupio telefonskim podacima. Želite\nli sada dodijeliti odobrenja?", hu_HU="Az irányítópultnak további jogosultságokra van szüksége a telefonadatok\neléréséhez. Meg szeretnéd most adni ezekez a jogosultságokat?", it_IT="La dashboard richiede ulteriori autorizzazioni per poter accedere ai dati del\ntelefono. Concedere adesso le autorizzazioni necessarie?", nl_NL="Het dashboard vereist extra autorisaties om toegang te krijgen tot de\ntelefoongegevens. Wil je deze autorisaties nu toekennen?", no_NO="Dashbordet mangler noen tillatelser for å få tilgang til telefondata. Vil du gi\ntillatelsene nå?", pl_PL="Pulpit wymaga dodatkowych uprawnień, aby uzyskać dostęp do danych telefonu.\nCzy chcesz przyznać te uprawnienia teraz?", pt_PT="O painel de instrumentos necessita de permissões adicionais para poder aceder aos\ndados do telefone. Queres conceder agora estas permissões?", ro_RO="Dashboard necesită drepturi suplimentare, pentru a putea accesa datele\ntelefonului. Doriţi să acordaţi acum aceste drepturi?", ru_RU="Информационная панель требует дополнительных разрешений для доступа к\nданным телефона. Хотите предоставить эти разрешения сейчас?", sk_SK="Dashboard vyžaduje dodatočné oprávnenia, aby ste mali prístup k údajom telefónu.\nChcete teraz udeliť tieto oprávnenia?", sl_SI="Nadzorna plošča potrebuje dodatna pooblastila za dostop do podatkov iz telefona.\nAli želite zdaj podeliti ta pooblastila?", sr_RS="Za kontrolnu tablu su potrebna dodatna ovlašćenja da bi mogla pristupiti\ntelefonskim podacima. Da li sada želite da dodelite ova ovlašćenja?", sv_SE="Instrumentbrädan behöver ytterligare behörigheter för att komma åt telefondata.\nVill du godkänna dessa behörigheter nu?", tr_TR="Gösterge panelinin telefon verilerine erişebilmesi için ek izinler gerekmektedir. Bu\nizinleri şimdi vermek istiyor musun?", uk_UA="Панель інструментів потребує додаткових дозволів для доступу до даних\nтелефону. Хочете надати ці дозволи зараз?")
texttool_globals_dialog_message___remove_shortcut_message = TextObject(bs_BA="Izbrisati prečicu?", cs_CZ="Smazat zkratku?", da_DK="Slet genvej?", de_DE="Shortcut löschen?", el_GR="Να διαγραφεί η συντόμευση;", en_GB="Delete shortcut?", es_ES="¿Borrar atajo?", fi_FI="Poistetaanko pikavalinta?", fr_FR="Effacer le raccourci?", hr_HR="Izbrisati prečac?", hu_HU="Parancsikon törlése?", it_IT="Cancellare shortcut?", nl_NL="Shortcut wissen?", no_NO="Slette snarvei?", pl_PL="Usunąć skrót?", pt_PT="Apagar atalho?", ro_RO="Ştergere comandă rapidă?", ru_RU="Удалить ярлык?", sk_SK="Shortcut vymazať?", sl_SI="Ali želite izbrisati bližnjico?", sr_RS="Izbrisati prečicu?", sv_SE="Radera genväg?", tr_TR="Kısayol silinsin mi?", uk_UA="Видалити ярлик?")
